import { expect } from 'chai';

import * as errors from '../src/errors.js';
import pkgExport, { errors as pkgErrors } from '../src/index.js';

describe('errors', function() {
	it('should be available on ".errors"', function(done) {
		expect(pkgErrors).to.be.a('object');
		done();
	});

	it('should include "BadTokenError"', function(done) {
		expect(pkgErrors.BadToken).to.equal(errors.BadToken);
		done();
	});

	it('should include "NoAuthizationProvidedError"', function(done) {
		expect(pkgErrors.NoAuthorizationProvided).to.equal(errors.NoAuthorizationProvided);
		done();
	});

	it('should include "PublicKeyNotFounddError"', function(done) {
		expect(pkgErrors.PublicKeyNotFound).to.equal(errors.PublicKeyNotFound);
		done();
	});

	it('should include "PublicKeyLookupFailedError"', function() {
		expect(pkgErrors.PublicKeyLookupFailed).to.equal(errors.PublicKeyLookupFailed);
	});
});
